blocks.content:
Instead of hardcoding HTML, you can create elements with JavaScript:

```javascript
// Create a new element
let newDiv = document.createElement("div");

// Set its content
newDiv.textContent = "Hello!";

// Set attributes and styles
newDiv.id = "myDiv";
newDiv.className = "container";
newDiv.style.color = "blue";

// Add it to the page
let container = document.querySelector("#main");
container.appendChild(newDiv);
```

**Common methods:**
- `document.createElement(tagName)` - Create a new element
- `element.appendChild(child)` - Add element as last child
- `element.insertBefore(newChild, referenceChild)` - Insert before a specific element
- `element.textContent = "text"` - Set the text
- `element.className = "class"` - Set CSS class

blocks.starterCode:
// Create a new paragraph element
let newParagraph = document.createElement("p");
newParagraph.textContent = "This paragraph was created with JavaScript!";
newParagraph.style.color = "purple";
newParagraph.style.fontSize = "18px";

// In a real page, we'd add it like this:
let body = document.body;
if (body) {
  body.appendChild(newParagraph);
  console.log("Added paragraph to page");
}

// Create a list
let list = document.createElement("ul");

let item1 = document.createElement("li");
item1.textContent = "First item";
list.appendChild(item1);

let item2 = document.createElement("li");
item2.textContent = "Second item";
list.appendChild(item2);

if (body) {
  body.appendChild(list);
  console.log("Added list to page");
}

blocks.content:
A common pattern is to **create elements from data**:

```javascript
let fruits = ["Apple", "Banana", "Orange"];
let list = document.querySelector("ul");

for (let fruit of fruits) {
  let item = document.createElement("li");
  item.textContent = fruit;
  list.appendChild(item);
}
```

This is powerful when combined with:
- Arrays of data
- User input
- API responses

You can build entire interfaces dynamically!

blocks.starterCode:
// Create a list from an array
let students = ["Alice", "Bob", "Charlie", "Diana"];

let studentList = document.createElement("ul");

for (let student of students) {
  let listItem = document.createElement("li");
  listItem.textContent = student;
  listItem.style.padding = "5px";
  listItem.style.marginBottom = "5px";
  studentList.appendChild(listItem);
}

// In a real page, add it to the DOM
let container = document.body;
if (container) {
  container.appendChild(studentList);
  console.log("Created student list with " + students.length + " items");
}

// Create cards from objects
let products = [
  { name: "Laptop", price: 999 },
  { name: "Mouse", price: 25 },
  { name: "Keyboard", price: 75 }
];

for (let product of products) {
  let card = document.createElement("div");
  card.style.border = "1px solid gray";
  card.style.padding = "10px";
  card.style.margin = "10px";

  let title = document.createElement("h3");
  title.textContent = product.name;

  let price = document.createElement("p");
  price.textContent = "$" + product.price;

  card.appendChild(title);
  card.appendChild(price);

  if (container) {
    container.appendChild(card);
  }
}

blocks.content:
You can also remove elements from the page:

```javascript
let element = document.querySelector("#oldElement");

// Remove it from the DOM
element.remove();

// Or, if you know the parent:
element.parentElement.removeChild(element);
```

Use this for:
- Deleting items from a list
- Clearing old content
- Cleaning up when not needed

